+        1 => c.is_ascii_alphanumeric(),
+        2 => c.is_ascii_alphabetic(),
+        3 => c == b' ' || c == b'\t',
+        4 => c.is_ascii_control(),
+        5 => c.is_ascii_digit(),
+        6 => c.is_ascii_graphic(),
+        7 => c.is_ascii_lowercase(),
+        8 => c.is_ascii_graphic() || c == b' ',
+        9 => c.is_ascii_punctuation(),
+        10 => c.is_ascii_whitespace(),
